solutions.javascript:
// Define a TypeScript function to parse the JSON string
function parseJson(jsonString: string): string {
    try {
        const obj = JSON.parse(jsonString);
        return JSON.stringify(obj.address);
    } catch (e) {
        return "Error parsing JSON";
    }
}

solutions.python:
class Solution:
    def parseJson(self, jsonString: str) -> str:
        try:
            obj = json.loads(jsonString)
            return json.dumps(obj['address'])
